  vData = Object.fromEntries(Object.entries(_d.D).map(([k,v]) => [k, {rPTS:v[0],VORP:v[1],VORPRank:v[2],BlendRank:v[3],POS:_d.P[v[4]],Age:v[5]||null,ExpertRank:v[6]||null,rPTS25:v[7]||null,ADP:v[8]||null}]));

  // ============================================================
  // NAME NORMALIZATION
  // ============================================================
  function normalize(s) {
    return s
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[.*]/g, "")
      .toLowerCase()
      .trim();
  }

  // "Witt, Bobby (SS KC)" -> "bobby witt"
  // "Guerrero Jr., Vladimir" -> "vladimir guerrero jr."
  // "Acuna Jr., Ronald" -> "ronald acuna jr."
  function cbsToKey(name) {
    let n = normalize(name);
    // Strip parenthetical (pos team)
    n = n.replace(/\s*\(.*?\)\s*/g, "").trim();
    if (n.includes(",")) {
      const parts = n.split(",").map((s) => s.trim());
      // CBS format: "Last Jr., First" or "Last, First"
      return parts[1] + " " + parts[0];
    }
    return n;
  }

  // ============================================================
  // MATCH CBS NAME TO VORP DATA — handles Jr./suffix mismatches
  // ============================================================
  function findVORP(cbsName) {
    if (!vData) return null;
    const key = cbsToKey(cbsName);

    // Direct match
    if (vData[key]) return { ...vData[key], _matched: key };

    // Try adding/removing "jr." suffix
    const withJr = key.endsWith(" jr.") ? key : key + " jr.";
    const withoutJr = key.replace(/ jr\.?$/, "");
    if (vData[withJr]) return { ...vData[withJr], _matched: withJr };
    if (vData[withoutJr]) return { ...vData[withoutJr], _matched: withoutJr };

    // Try "ii", "iii" suffixes
    for (const suf of [" ii", " iii", " iv"]) {
      if (vData[key + suf]) return { ...vData[key + suf], _matched: key + suf };
      const stripped = key.replace(new RegExp(suf.replace('.','') + '$'), '');
      if (stripped !== key && vData[stripped]) return { ...vData[stripped], _matched: stripped };
    }

    // Fuzzy: match on last name + first name initial
    const parts = key.split(/\s+/);
    if (parts.length >= 2) {
      const firstName = parts[0];
      const lastName = parts[parts.length - 1].replace(/ jr\.?$/, "");
      for (const [name, data] of Object.entries(vData)) {
        if (name.includes(lastName) && name.startsWith(firstName.charAt(0))) {
          return { ...data, _matched: name };
        }
      }
      // Even more lenient: just last name + first 3 chars
      const first3 = firstName.substring(0, 3);
      for (const [name, data] of Object.entries(vData)) {
        if (name.includes(lastName) && name.includes(first3)) {
          return { ...data, _matched: name };
        }
      }
    }

    return null;
  }

  // ============================================================
  // SAFELY ACCESS CBS APP
  // ============================================================
  function getMainApp() {
    try { if (APP.mainapp) return APP.mainapp; } catch (e) {}
    try { if (typeof mainapp !== "undefined") return mainapp; } catch (e) {}
    return null;
  }

